  9→function handlerParams(params: Record<string, any>): Record<string, any> {
 10→    const intact_columns = difference(Object.keys(params), [
 11→        'decrypt_config',
 12→        'hash_filter',
 13→        'page',
 14→        'per_page',
 15→        'sys_lang',
 16→    ])
 17→    return { ...params, intact_columns, sys_site: 'CHN' }
