163→export interface ExtractSlotsResult {
164→    intent: 'analyze' | 'new_query'
165→    query_type: 'project' | 'person' | 'global' | 'unknown'
166→    slots_complete: boolean
167→    member_type: 'group' | 'individual' | ''
168→    members: string[]
169→    project_names: string[]
170→    period_start: string
171→    period_end: string
172→    period_raw: string
173→    reply: string
174→    conversation_id: string
175→}
176→
177→/**
178→ * 从 AI 原始文本中解析槽位 JSON，兼容 markdown 代码块包裹
179→ */
180→function parseSlotJson(text: string): ExtractSlotsResult {
181→    const fallback: ExtractSlotsResult = {
182→        intent: 'new_query',
183→        query_type: 'unknown',
184→        slots_complete: false,
185→        members: [],
186→        member_type: '',
187→        project_names: [],
188→        period_start: '',
189→        period_end: '',
190→        period_raw: '',
191→        reply: '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
192→        conversation_id: '',
193→    }
194→    const match = text.match(/\{[\s\S]*\}/)
195→    if (!match) {
196→        console.warn('[AiSlots] no JSON found in answer', text.slice(0, 500))
197→        return fallback
198→    }
199→    try {
200→        const data = JSON.parse(match[0])
201→        return {
202→            intent: data.intent ?? 'new_query',
203→            query_type: data.query_type ?? 'unknown',
204→            slots_complete: !!data.slots_complete,
205→            members: data.members ?? [],
206→            member_type: data.member_type ?? '',
207→            project_names: data.project_names ?? [],
208→            period_start: data.period_start ?? '',
209→            period_end: data.period_end ?? '',
210→            period_raw: data.period_raw ?? '',
211→            reply: data.reply ?? '',
212→            conversation_id: '',
213→        }
214→    } catch {
215→        console.warn('[AiSlots] JSON parse failed', match[0].slice(0, 500))
216→        return fallback
217→    }
218→}
219→
220→async function extractSlots(params: {
221→    message: string
222→    conversation_id?: string
223→    has_existing_context?: boolean
224→    available_groups?: string[]
225→    available_members?: string[]
226→    previous_context?: { query_type: string; member_type: string; members: string[]; project_names: string[]; period_start: string; period_end: string }
227→}): Promise<ExtractSlotsResult | null> {
228→    try {
229→        const res = await axiosPostWithInt(BASE + 'daily-report/ai/extract-slots', handlerParams(params))
230→        // oa-server 返回 { message, ai_analysis_config }，oa-core TransferRequestService 做 blocking AI，结果在 ai_result
231→        const aiResult = res.data?.ai_result ?? ''
232→        if (!aiResult) {
233→            return null
234→        }
235→        return parseSlotJson(aiResult)
236→    } catch (e) {
237→        Message.error(e?.error_msg || '意图识别失败')
238→        return null
239→    }
240→}
