296→/**
297→ * 发送消息，返回 fetch Response（SSE）
298→ * 调用方通过 response.body.getReader() 读取流
299→ */
300→async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
301→    const url = BASE + 'daily-report/ai/ask'
302→    const headers: Record<string, string> = {
303→        'Content-Type': 'application/json',
304→    }
305→    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
306→    const { system_prompt, history, ...restParams } = params
307→    const payload: Record<string, any> = {
308→        ...restParams,
309→        response_format: 'stream',
310→        ai_analysis_config: {
311→            system_prompt: system_prompt || '',
312→            target_field: 'query',
313→            history: history || [],
314→        },
315→    }
316→
317→    return fetch(url, {
318→        method: 'POST',
319→        headers,
320→        credentials: 'include',
321→        signal,
322→        body: JSON.stringify(handlerParams(payload)),
323→    })
324→}
