372→    public function sessionMessages(Request $request): JsonResponse
373→    {
374→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
375→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
376→            return $this->responseJsonFail('无权限');
377→        }
378→        $sessionId = $request->input('session_id');
379→
380→        // 校验会话归属
381→        $session = DB::table('daily_report_ai_sessions')
382→            ->where('id', $sessionId)
383→            ->where('sfuser_id', $sfuserId)
384→            ->whereNull('deleted_at')
385→            ->first();
386→
387→        if (!$session) {
388→            return $this->responseJsonSuccess(['list' => []]);
389→        }
390→
391→        $contextMaxChars = 5000;
392→        $messages = DB::table('daily_report_ai_messages')
393→            ->where('session_id', $sessionId)
394→            ->orderBy('id')
395→            ->get(['id', 'role', 'content', 'created_at']);
396→
397→        // context 消息截断，减少首次加载体积
398→        foreach ($messages as $msg) {
399→            if ($msg->role === 'context') {
400→                $fullLength = mb_strlen($msg->content);
401→                if ($fullLength > $contextMaxChars) {
402→                    $msg->content = mb_substr($msg->content, 0, $contextMaxChars);
403→                    $msg->is_truncated = true;
404→                    $msg->full_length = $fullLength;
405→                }
406→            }
407→        }
408→
409→        return $this->responseJsonSuccess(['list' => $messages]);
410→    }
