415→    public function contextMore(Request $request): JsonResponse
416→    {
417→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
418→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
419→            return $this->responseJsonFail('无权限');
420→        }
421→        $messageId = $request->input('message_id');
422→        $offset = (int)$request->input('offset', 0);
423→        $limit = 5000;
424→
425→        // 校验消息归属：message → session → sfuser
426→        $msg = DB::table('daily_report_ai_messages as m')
427→            ->join('daily_report_ai_sessions as s', 's.id', '=', 'm.session_id')
428→            ->where('m.id', $messageId)
429→            ->where('m.role', 'context')
430→            ->where('s.sfuser_id', $sfuserId)
431→            ->whereNull('s.deleted_at')
432→            ->select('m.content')
433→            ->first();
434→
435→        if (!$msg) {
436→            return $this->responseJsonFail('消息不存在');
437→        }
438→
439→        $fullLength = mb_strlen($msg->content);
440→        $chunk = mb_substr($msg->content, $offset, $limit);
441→        $hasMore = ($offset + $limit) < $fullLength;
442→
443→        return $this->responseJsonSuccess([
444→            'content' => $chunk,
445→            'offset' => $offset,
446→            'has_more' => $hasMore,
