578→            'message' => $message,
579→            'previous_context' => $previousContext,
580→            'available_groups' => $availableGroups,
581→            'member_count' => count($availableMembers),
582→            'project_count' => count($projectList),
583→        ]);
584→
585→        return $this->responseJsonSuccess([
586→            'message' => $message,
