595→    // ----------------------------------------------------------------
596→    // 发送消息（SSE 流式）
597→    // ----------------------------------------------------------------
598→
599→    public function ask(Request $request): JsonResponse
600→    {
601→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
602→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
603→            \Log::info('[lbl][0416-AI日报][AiAsk] 无权限', ['sfuser_id' => $sfuserId]);
604→            return $this->responseJsonFail('无权限');
605→        }
606→        $roleId = $request->input('role_id');
607→        $sessionId = $request->input('session_id');
608→        $message = $request->input('message');
609→        $reportContext = $request->input('report_context', '');
610→        $reportContextRaw = $request->input('report_context_raw', '');
611→
612→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
613→        if (str_starts_with($reportContext, 'gz:')) {
614→            $decoded = base64_decode(substr($reportContext, 3), true);
615→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
616→        }
617→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
618→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
619→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
620→            'bytes' => strlen($reportContext),
621→            'chars' => mb_strlen($reportContext),
622→        ]);
623→
624→        // 校验角色归属
625→        $role = DB::table('daily_report_ai_roles')
626→            ->where('id', $roleId)
627→            ->where('sfuser_id', $sfuserId)
628→            ->whereNull('deleted_at')
629→            ->first();
630→
631→        if (!$role) {
632→            return $this->responseJsonFail('角色不存在');
633→        }
634→
635→        // 创建或复用会话
636→        if (!$sessionId) {
637→            $title = mb_substr($message, 0, 20);
638→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
639→                'sfuser_id' => $sfuserId,
640→                'role_id' => $roleId,
641→                'title' => $title,
642→                'created_at' => now(),
643→                'updated_at' => now(),
644→            ]);
645→        } else {
646→            $sessionRow = DB::table('daily_report_ai_sessions')
647→                ->where('id', $sessionId)
648→                ->where('sfuser_id', $sfuserId)
649→                ->whereNull('deleted_at')
650→                ->first();
651→            if (!$sessionRow) {
652→                return $this->responseJsonFail('会话不存在');
653→            }
654→        }
655→
656→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
657→        if (str_starts_with($reportContextRaw, 'gz:')) {
658→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
659→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
660→        }
661→
662→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
663→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
664→        if (!empty($contextToStore)) {
665→            DB::table('daily_report_ai_messages')->insert([
666→                'session_id' => $sessionId,
667→                'role' => 'context',
668→                'content' => $contextToStore,
669→                'created_at' => now(),
670→            ]);
671→        }
672→
673→        // 保存用户消息
674→        DB::table('daily_report_ai_messages')->insert([
675→            'session_id' => $sessionId,
676→            'role' => 'user',
677→            'content' => $message,
678→            'created_at' => now(),
679→        ]);
680→
681→        // 更新会话时间
682→        DB::table('daily_report_ai_sessions')
683→            ->where('id', $sessionId)
684→            ->update(['updated_at' => now()]);
685→
686→        // 构建发送给 AI 的内容
687→        $queryParts = [];
688→        if (!empty($reportContext)) {
689→            $queryParts[] = "[日报数据]\n{$reportContext}";
690→        }
691→        $queryParts[] = $message;
692→        $query = implode("\n\n---\n\n", $queryParts);
693→
694→        \Log::info('[lbl][0416-AI日报][AiAsk] request', [
695→            'session' => $sessionId,
696→            'query_len' => mb_strlen($query),
697→        ]);
698→
699→        // 返回 query + session_id，AI streaming 由 oa-core TransferRequestService 完成
700→        return $this->responseJsonSuccess([
701→            'query' => $query,
702→            'session_id' => $sessionId,
703→        ]);
704→    }
